<?php
namespace Tests\Feature\Hr;
use Illuminate\Support\Facades\Artisan; use Illuminate\Support\Facades\Schema; use Tests\TestCase;
class HrPhase4CEngagementRollbackTest extends TestCase { use RefreshHrDatabase; public function test_engagement_schema_exists():void{$this->assertTrue(Schema::hasColumns('hr_surveys',['questions','is_anonymous','minimum_report_count']));$this->assertTrue(Schema::hasColumns('hr_survey_responses',['respondent_hash','answers','enps_score']));$this->assertTrue(Schema::hasColumns('hr_recognitions',['sender_employee_id','recipient_employee_id','is_public']));}public function test_rollback_preserves_training_tables():void{Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>3]);$this->assertFalse(Schema::hasTable('hr_surveys'));$this->assertTrue(Schema::hasTable('hr_training_courses'));$this->assertTrue(Schema::hasColumn('hr_shift_templates','required_training_course_id'));} }
